但props是对象时

与数组相似，但多了数据验证的功能

参考代码：

const cpn = &#123;
    template:'#cpn',
    props:&#123;
        // 基础的类型检查(null匹配任何类型)
        propA:Number,
        // 多个可能的类型
        propB:[String,Number],
        // 必填的字符串
        propC:&#123;
            type:String,
            required:true
        &#125;,
        // 带有默认值的数字
        propD:&#123;
            type:Number,
            default:666
        &#125;,
        // 带有默认值的对象
        propE:&#123;
            type:Object,
            // 对象或数组默认值必须从函数获取
            default: function()&#123;
                return &#123;message:'hello'&#125;
            &#125;
        &#125;,
        // 自定义验证函数
        propF:&#123;
            validator:function(value)&#123;
                // 这个值必须匹配下列字符串中的一个
                return ['HTML','CSS','JavaScript','Vue'].indexOf(value) !== -1
            &#125;
        &#125;
    &#125;
&#125;;


